INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Usage metering$q$, $q$Ingests raw product usage events in real time to track consumption at scale without added engineering overhead.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Flexible price modeling$q$, $q$Supports subscription, usage-based, and hybrid pricing structures configured without custom code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Automated invoicing$q$, $q$Generates granular, accurate invoices with support for backdating and backfilling usage data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Spend controls and alerts$q$, $q$Sends usage alerts and automates workflows based on customer consumption patterns.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Experience Kit$q$, $q$Provides customer-facing billing dashboards and checkout flows for self-serve plan management.$q$, 4);
