INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Finance system integrations$q$, $q$Connects to Salesforce, NetSuite, and data warehouses for downstream reporting.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$ASC 606-aligned workflows$q$, $q$Supports audit-ready revenue recognition processes for finance and accounting teams.$q$, 7);
