INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$No published pricing, making it hard to budget without a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Aimed at mid-market and enterprise B2B software companies rather than small businesses$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Requires engineering effort to pipe usage events into the platform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Now operating as an Adyen subsidiary, which may affect independent roadmap direction$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Complex hybrid pricing configurations can carry a learning curve$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Not a payment processor on its own; relies on integrations for collection$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$What is Orb used for?$q$, $q$Orb is used by B2B software companies to meter product usage and automate billing, invoicing, and revenue recognition for usage-based and hybrid pricing models.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$How much does Orb cost?$q$, $q$Orb's pricing is custom and based on billings (invoice value issued through Orb) and events (usage records ingested), with Core, Advanced, and Enterprise tiers available on request.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Is Orb a payment processor?$q$, $q$No, Orb is a billing and metering engine that integrates with finance, tax, and payment systems rather than processing payments itself.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Who owns Orb?$q$, $q$Orb was acquired by Adyen in a deal announced in June 2026 and closed on July 1, 2026, and now operates as a wholly owned Adyen subsidiary.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$What companies use Orb?$q$, $q$Publicly named Orb customers include Vercel, Supabase, Redis, and LaunchDarkly.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Does Orb support hybrid pricing models?$q$, $q$Yes, Orb supports subscription, usage-based, and hybrid pricing combining both within the same contract.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$What is the difference between Orb's Core, Advanced, and Enterprise tiers?$q$, $q$Core covers essential metering and invoicing; Advanced adds a platform fee plus data warehouse sync, CRM/ERP integrations, and premium support; Enterprise adds dedicated support and enterprise SLAs.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Who are Orb's main competitors?$q$, $q$Orb competes with Metronome, Zuora, Chargebee, and Stripe Billing in the usage-based billing space.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Metering AI and API-based products$q$, $q$AI and infrastructure companies bill customers by tokens, API calls, or compute consumption using Orb's real-time event ingestion.$q$, $q$AI and developer-tools companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Consumption pricing for cloud platforms$q$, $q$Cloud infrastructure providers manage complex, tiered consumption pricing and invoicing at scale.$q$, $q$Cloud infrastructure providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Moving from flat subscriptions to hybrid pricing$q$, $q$Enterprise SaaS vendors add usage-based components to existing seat-based subscription pricing.$q$, $q$Enterprise B2B SaaS finance and product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Core$q$, $q$Custom$q$, $q$Contact sales$q$, NULL, $q$["Real-time event ingestion","Hybrid and usage-based billing","Automated price changes","Orb invoicing","Finance and tax integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Advanced$q$, $q$Custom plus platform fee$q$, $q$Contact sales$q$, NULL, $q$["Everything in Core","Data warehouse sync","Salesforce integration","NetSuite integration","Customer hierarchy","Premium support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$Enterprise$q$, $q$Custom plus platform fee$q$, $q$Contact sales$q$, NULL, $q$["Everything in Advanced","Enterprise-grade SLAs for accuracy, uptime, and support","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Orb is a billing and revenue automation platform purpose-built for B2B software companies that need to charge for usage rather than, or in addition to, flat subscriptions. Instead of hard-coding pricing logic into an application, teams send raw usage events to Orb and define pricing rules on top, letting finance and product teams change pricing without waiting on an engineering sprint.$q$, $q$Founded in 2021 by former Asana engineers Alvaro Morales and Kshitij Grover, Orb launched publicly in 2023 and quickly became known among AI infrastructure, cloud platform, and developer-tools companies that bill customers by API calls, compute, tokens, or other consumption metrics. In 2026 the company was acquired by payments giant Adyen to unify billing and payments infrastructure for enterprise merchants.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Orb's core is real-time event ingestion paired with flexible price modeling, so a company can support tiered, volume, per-unit, or hybrid subscription-plus-usage pricing from a single system. Invoicing supports backdating and backfilling usage data, which matters for companies that need to correct or reconcile metering after the fact.$q$, $q$Beyond billing mechanics, Orb includes spend controls and usage alerts, a customer-facing Experience Kit for dashboards and self-serve checkout, revenue simulation tools to model the financial impact of a pricing change before shipping it, and audit-ready workflows aligned to ASC 606 revenue recognition standards.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a1062364-3f5b-45dc-b882-5a0283cbb0a9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Orb does not publish flat-rate pricing. Instead, cost is based on two metrics: billings, the total value of invoices issued to a company's end customers through Orb, and events, the volume of raw usage records ingested into the platform.$q$, $q$Orb offers three named tiers: Core, Advanced, and Enterprise. Core covers the essential metering, invoicing, and pricing engine; Advanced (the most commonly adopted tier) adds a platform fee along with data warehouse sync, Salesforce and NetSuite integrations, customer hierarchy, and premium support; Enterprise adds dedicated support and enterprise-grade SLAs. All tiers require contacting Orb's sales team for a quote.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Agentless SideScanning$q$, $q$Scans cloud workloads directly from the provider's infrastructure layer without deploying agents to every resource.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Unified Data Model$q$, $q$Correlates vulnerabilities, misconfigurations, identity risk, and exposed data into prioritized attack-path context.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Cloud security posture management$q$, $q$Continuously monitors AWS, Azure, and GCP configurations against security best practices and benchmarks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Cloud infrastructure entitlement management$q$, $q$Identifies excessive or risky permissions across cloud identities and roles.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Runtime protection via Orca Sensor$q$, $q$Adds runtime observability and threat detection alongside the agentless baseline scanning.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Compliance monitoring$q$, $q$Tracks adherence to frameworks such as SOC 2, PCI-DSS, and HIPAA across the cloud estate.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$AI security posture management$q$, $q$Assesses security risk for AI models and agentic workloads deployed in the cloud.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Workflow integrations$q$, $q$Connects findings and alerts into tools like Slack, Jira, ServiceNow, Splunk, and GitHub.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$No agents to deploy or maintain, reducing operational overhead and coverage gaps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Unified Data Model provides full-stack risk context across workloads, identity, and data$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Fast onboarding compared to agent-based cloud security tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Attack-path prioritization helps reduce alert fatigue for security teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Broad multi-cloud coverage across AWS, Azure, and GCP$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Backed by well-known enterprise customers such as Autodesk and Swiggy$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$No public pricing; requires a sales engagement to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Purely agentless scanning historically missed some runtime-only telemetry, though Orca Sensor now addresses this gap$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Enterprise-oriented pricing may be costly for smaller organizations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Can surface a large volume of findings that require tuning and prioritization$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Competes in a crowded, fast-consolidating CNAPP market$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Best value requires adopting multiple modules rather than a single point solution$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$What does Orca Security do?$q$, $q$Orca Security is a cloud-native application protection platform that detects, prioritizes, and helps remediate security risks and compliance issues across AWS, Azure, GCP, and Kubernetes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Is Orca Security agent-based or agentless?$q$, $q$Orca is primarily agentless, using SideScanning to read workload data from the cloud provider's infrastructure layer, though it also offers an optional Orca Sensor for runtime protection.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$How much does Orca Security cost?$q$, $q$Orca does not publish pricing; cost is quote-based, determined by workload count and the modules purchased.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Where is Orca Security headquartered?$q$, $q$Orca Security is headquartered in Tel Aviv, Israel, with additional operations in the United States including Portland, Oregon.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$What cloud providers does Orca Security support?$q$, $q$Orca supports AWS, Microsoft Azure, and Google Cloud Platform, along with Kubernetes environments.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Who founded Orca Security?$q$, $q$Orca Security was founded in 2018 by Avi Shua and Gil Geron.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$What is Orca Security's SideScanning technology?$q$, $q$SideScanning is Orca's patented method of scanning cloud workloads directly from the provider's infrastructure layer without installing agents on individual resources.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Who are Orca Security's main competitors?$q$, $q$Orca competes with Wiz, Palo Alto Networks Prisma Cloud, Lacework, and Aqua Security in the CNAPP market.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Multi-cloud risk visibility$q$, $q$Security teams get unified visibility into vulnerabilities and misconfigurations across AWS, Azure, and GCP from a single platform.$q$, $q$Cloud security and DevSecOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Compliance monitoring$q$, $q$Organizations track adherence to frameworks like SOC 2, PCI-DSS, and HIPAA across dynamic cloud environments.$q$, $q$Compliance and risk teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Fast onboarding for large cloud estates$q$, $q$Enterprises with thousands of cloud workloads gain visibility without deploying and managing agents on every resource.$q$, $q$Enterprise security operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$Enterprise$q$, $q$Custom$q$, $q$Annual contract, contact sales$q$, NULL, $q$["Agentless SideScanning across AWS, Azure, and GCP","Unified Data Model and attack-path prioritization","CSPM, CWPP, and CIEM modules","Compliance monitoring","Integrations with Slack, Jira, ServiceNow, Splunk, and GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Orca Security is a cloud security platform that gives security teams full visibility into risk across AWS, Azure, Google Cloud, and Kubernetes without installing agents on every workload. It was founded in 2018 by Avi Shua and Gil Geron and is headquartered in Tel Aviv, Israel, with additional operations in the United States.$q$, $q$The company built its reputation on SideScanning, a patented agentless scanning approach that reads workload data directly from the cloud provider's control plane. This lets security teams onboard an entire cloud estate in minutes rather than deploying agents to thousands of individual resources, a common bottleneck with older cloud workload protection tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Orca combines cloud security posture management (CSPM), cloud workload protection (CWPP), cloud infrastructure entitlement management (CIEM), vulnerability management, and compliance monitoring into a single platform built on a Unified Data Model, so findings across categories are correlated into prioritized attack paths instead of siloed alert feeds.$q$, $q$More recent additions include Orca Sensor for runtime detection and response, an AI reasoning engine that automates parts of triage and remediation, AI security posture management for organizations deploying AI models and agents in the cloud, and code security scanning that catches risks before they reach production. The platform integrates with more than 20 tools including Slack, Jira, ServiceNow, Splunk, and GitHub.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de412e9f-bb56-438d-8972-125d8b06d414', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Orca Security does not publish pricing on its website. Cost is determined through a custom, sales-led process typically based on the number of cloud workloads, accounts, and modules (such as CIEM, AI security, or code security) an organization needs.$q$, $q$Prospective customers request a personalized demo, after which Orca's sales team provides a quote scoped to the size and complexity of the customer's cloud environment.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$Purchase order management$q$, $q$Creates, sends, and tracks purchase orders across all vendors from a single dashboard.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$Accounts payable automation$q$, $q$Automates invoice capture, matching, and approval to speed up and de-risk vendor payments.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$Spend approval workflows$q$, $q$Enforces pre-configured approval policies so purchases stay within budget before they happen.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$Virtual cards$q$, $q$Issues virtual cards for controlled, trackable payments to any vendor.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$Order.co AI$q$, $q$Analyzes purchase history to recommend better prices and alternative products.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$Custom catalogs$q$, $q$Lets teams buy from pre-approved vendor catalogs to speed up purchasing and cut rogue spend.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$Accounting and ERP sync$q$, $q$Syncs spend data with accounting and ERP systems for accurate forecasting and reporting.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$Spend analytics$q$, $q$Provides reporting and dashboards for visibility into spend by team, vendor, and category.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$Consolidates purchasing across many vendors into one platform and workflow$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$Automates accounts payable, reducing manual invoice data entry$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$Built-in approval policies improve spend control and compliance$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$AI-driven price and product matching can reduce product costs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$Well suited to multi-location and multi-entity organizations$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$Strong reporting and visibility into company-wide spend$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$Pricing is not published and requires a custom quote and demo$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a442a095-0271-47c3-9bde-0e4be198b2c6', $q$Best suited to mid-size and multi-location organizations rather than very small businesses$q$, 1);
