INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$API-first design integrates into existing CRM and ERP stacks$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$Positioned as faster to implement than legacy enterprise billing suites$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$No public pricing; requires a sales conversation to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$Smaller company than incumbents like Zuora, so third-party ecosystem is less extensive$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$Implementation can require meaningful setup for complex billing rules$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$Best suited to companies with meaningful transaction volume rather than very early-stage startups$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$Some users cite reporting flexibility as an area for improvement$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$Custom pricing complexity can extend sales and onboarding cycles$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$What is Ordway used for?$q$, $q$Ordway is used for subscription billing, invoicing, and revenue recognition automation across the quote-to-cash cycle for SaaS and fintech companies.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$Who founded Ordway?$q$, $q$Ordway was founded in 2018 by Sameer Gulati, a former Zuora product manager who serves as CEO.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$How much does Ordway cost?$q$, $q$Ordway does not publish pricing; cost is quote-based depending on transaction volume and billing complexity.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$Does Ordway support usage-based billing?$q$, $q$Yes, Ordway supports subscription, usage-based, and hybrid pricing models.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$Does Ordway handle revenue recognition?$q$, $q$Yes, Ordway automates revenue recognition aligned to ASC 606 and IFRS 15 standards.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$What systems does Ordway integrate with?$q$, $q$Ordway integrates with CRM, ERP, and payment systems such as Salesforce, NetSuite, and Stripe through an API-first architecture.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$Where is Ordway headquartered?$q$, $q$Ordway is headquartered in Washington, D.C., United States.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$Who are Ordway's main competitors?$q$, $q$Ordway competes with Zuora, Chargebee, Recurly, and BillingPlatform in the subscription billing space.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$Hybrid subscription and usage billing$q$, $q$SaaS companies combine flat subscription fees with metered usage charges in a single billing system.$q$, $q$Mid-market SaaS finance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$Revenue recognition compliance$q$, $q$Finance teams automate ASC 606 and IFRS 15 revenue recognition schedules instead of using spreadsheets.$q$, $q$SaaS controllers and accounting teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$Multi-entity global billing$q$, $q$Companies with multiple legal entities or currencies centralize billing operations on one platform.$q$, $q$Global SaaS and fintech companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$Custom$q$, $q$Custom$q$, $q$Contact sales$q$, NULL, $q$["Subscription and usage-based billing","Automated invoicing and dunning","Revenue recognition automation","CPQ and quoting","Multi-entity and multi-currency support","SaaS metrics reporting"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ordway is a billing and revenue automation platform built for SaaS, cloud, and fintech companies managing subscription, usage-based, or hybrid pricing. It was founded in 2018 by Sameer Gulati, a former Zuora product manager, and is headquartered in Washington, D.C.$q$, $q$The platform covers the full quote-to-cash lifecycle, from quoting and contract creation through invoicing, payment collection, and revenue recognition, aiming to replace the spreadsheets and manual processes many growing SaaS finance teams rely on before adopting dedicated billing software.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes flexible subscription and usage-based billing, automated invoicing and dunning for failed payments, and revenue recognition automation aligned to ASC 606 and IFRS 15 standards. Ordway also supports CPQ-style quoting, multi-entity and multi-currency billing, and reporting on core SaaS metrics like MRR, churn, and revenue waterfall.$q$, $q$Because the platform is API-first, it is designed to integrate with existing CRM, ERP, and payment systems such as Salesforce, NetSuite, and Stripe rather than requiring a company to replace its broader finance stack.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cf66e303-0e7b-4d2e-b35e-ae3a7ac44901', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Ordway does not publish pricing on its website. Cost is determined through a custom sales process based on transaction volume, billing complexity, and the number of entities or currencies a company needs to support.$q$, $q$Prospective customers contact Ordway's sales team directly to scope requirements and receive a quote.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Data integration and harmonization$q$, $q$Connects and cleans workforce data from multiple HR and finance systems into a trusted baseline.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Interactive org charts$q$, $q$Visualizes organizational structure and headcount through dynamic, explorable charts and dashboards.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Scenario modeling$q$, $q$Simulates alternative organizational designs and compares their cost and structural impact in real time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Skills and competency analysis$q$, $q$Maps skills taxonomies by role and visualizes skills distribution and gaps across the workforce.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Workforce demand and supply forecasting$q$, $q$Models demand, supply, and gap assumptions to plan future headcount needs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Collaborative planning$q$, $q$Supports role-based collaboration among HR and business stakeholders on org design projects.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$HR system integrations$q$, $q$Integrates with core HCM platforms such as Workday and SAP SuccessFactors.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Reporting and dashboards$q$, $q$Provides reporting views for tracking org design and workforce planning outcomes.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Purpose-built for organizational design rather than adapted from generic BI tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Strong scenario modeling for restructuring and M&A workforce planning$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Visual, intuitive org charting even with large, complex datasets$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Dedicated skills-based workforce planning capability$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Used by large enterprises for complex reorganization projects$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Backed by institutional investment including Morgan Stanley, signaling enterprise credibility$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Pricing is not public and requires an enterprise sales process$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Steep learning curve when building custom data models$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Best suited to larger organizations with dedicated HR or org design analysts$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Effectiveness depends on the quality of underlying HR data fed into the platform$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Competes with workforce planning modules bundled into broader HCM suites$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Not designed as a system of record, so it requires integration with a core HRIS$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$What is Orgvue used for?$q$, $q$Orgvue is used for organizational design and workforce planning, including visualizing org structure, modeling restructuring scenarios, and analyzing workforce skills.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Who founded Orgvue?$q$, $q$Orgvue was founded in 2005 by Rupert Morrison and is headquartered in London, United Kingdom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$How much does Orgvue cost?$q$, $q$Orgvue does not publish pricing; it is sold through a custom, quote-based enterprise sales process.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Does Orgvue replace a core HR system?$q$, $q$No, Orgvue is typically used alongside a core HCM system such as Workday or SAP SuccessFactors rather than replacing it.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$What kind of companies use Orgvue?$q$, $q$Orgvue is used by large and mid-size enterprises undertaking complex restructuring, M&A integration, or strategic workforce planning.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Does Orgvue support skills-based workforce planning?$q$, $q$Yes, Orgvue includes skills and competency analysis tools that map skills by role and identify workforce capability gaps.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Can Orgvue model different organizational scenarios?$q$, $q$Yes, Orgvue's scenario modeling lets users compare the cost and structural impact of alternative organizational designs in real time.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Who are Orgvue's main competitors?$q$, $q$Orgvue competes with Visier, ChartHop, and the workforce planning modules within Workday and SAP SuccessFactors.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Enterprise restructuring$q$, $q$HR and strategy teams model the cost and structural impact of a reorganization before implementing it.$q$, $q$HR and organizational design teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$M&A workforce integration$q$, $q$Companies plan how to merge two organizational structures and workforces following an acquisition.$q$, $q$M&A integration and HR leadership$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Skills-based workforce planning$q$, $q$Organizations map current skills against future demand to guide hiring, reskilling, and workforce strategy.$q$, $q$People analytics and workforce planning teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$Custom$q$, $q$Custom$q$, $q$Contact sales$q$, NULL, $q$["Data integration and harmonization","Interactive org charts and dashboards","Scenario modeling","Skills and competency analysis","Workforce demand and supply forecasting"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Orgvue is a workforce planning and organizational design platform used by large enterprises to model and visualize how their organization is structured and how it might need to change. Founded in 2005 by Rupert Morrison and headquartered in London, the company grew out of organizational design consulting work into a dedicated software product.$q$, $q$Rather than replacing a core HR information system, Orgvue sits alongside systems like Workday or SAP SuccessFactors, pulling in workforce data to support the kind of scenario planning, restructuring, and skills analysis that transactional HR systems are not built to do.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Orgvue's foundation is data integration and harmonization: connecting and cleaning workforce data from multiple source systems into a single trusted baseline that can be segmented by organization, position, and people dimensions. On top of that data, users build interactive org charts and dashboards for a clear, real-time view of the organization.$q$, $q$The platform's scenario modeling lets teams simulate alternative organizational designs, comparing cost and structural impact side by side to build consensus before committing to a restructuring plan. Its skills and competency analysis maps the skills required for each role, visualizes skills distribution across the workforce, and highlights gaps against future workforce demand.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cd26b5d-cf7d-49f1-82c5-0fb63f754a1f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Orgvue does not publish pricing publicly. As an enterprise platform aimed at large organizations undertaking complex workforce planning projects, it is sold through a custom, quote-based sales process.$q$, $q$Pricing typically depends on the number of users, the size of the workforce being modeled, and which modules, such as scenario modeling or skills analysis, a customer needs.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$AI content detector$q$, $q$Identifies text generated by AI models such as ChatGPT, Claude, Gemini, and Grok.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Plagiarism checker$q$, $q$Detects global, paraphrased, and patchwork plagiarism against web content.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Fact checker$q$, $q$Cross-references written claims against reputable sources to flag potential inaccuracies.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$SEO content optimizer$q$, $q$Analyzes content against SEO best practices to improve search performance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Chrome extension$q$, $q$Allows in-browser scanning of content without leaving the page being reviewed.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Website and domain scanning$q$, $q$Scans entire websites or domains to audit content for AI use and plagiarism over time.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Team management$q$, $q$Lets agencies and publishers manage multiple seats and shared credit pools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$API access$q$, $q$Provides programmatic access to AI and plagiarism detection on the Enterprise plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Combines AI detection, plagiarism checking, and fact checking in one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$High claimed accuracy against major AI models and plagiarism sources$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$API access available for enterprise workflows$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Chrome extension enables quick in-browser scanning$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Team seat management suits agencies and publishers$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Frequently updated to track new AI model outputs$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Credit-based pricing can become expensive at high content volumes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$No unlimited free tier for ongoing use$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$AI detection tools, including this one, can produce false positives on human-written text$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Smaller company size means more limited enterprise support infrastructure$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Lowest monthly price requires committing to annual billing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Combined AI and plagiarism scans consume credits faster than single-purpose checks$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$What does Originality.ai do?$q$, $q$Originality.ai detects AI-generated text, checks for plagiarism, and fact-checks written content for publishers, marketers, and educators.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$How much does Originality.ai cost?$q$, $q$Originality.ai's Pro plan starts at 14.95 dollars per month (12.95 dollars per month billed annually), with an Enterprise plan and pay-as-you-go credits also available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$How accurate is Originality.ai's AI detector?$q$, $q$Originality.ai claims high accuracy detecting text from major AI models such as ChatGPT, Claude, Gemini, and Grok, though no AI detector is guaranteed to be error-free.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Does Originality.ai check for plagiarism?$q$, $q$Yes, Originality.ai includes a plagiarism checker that detects global, paraphrased, and patchwork plagiarism.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Who founded Originality.ai?$q$, $q$Originality.ai was founded in 2022 by Jon Gillham and Conor Watt.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Does Originality.ai have an API?$q$, $q$Yes, API access is included on the Enterprise plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$What is a credit in Originality.ai?$q$, $q$One credit covers approximately 100 words of AI-only scanning, while combined AI and plagiarism scans use two credits per 100 words.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Who are Originality.ai's main competitors?$q$, $q$Originality.ai competes with Copyleaks, Turnitin, GPTZero, and Winston AI.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$SEO content quality control$q$, $q$Content marketing teams verify articles are original and human-reviewed before publishing for search.$q$, $q$SEO and content marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Agency content auditing$q$, $q$Agencies scan client websites and deliverables to confirm content meets originality standards.$q$, $q$Content and marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Academic integrity checks$q$, $q$Educators check submitted work for AI-generated text and plagiarism.$q$, $q$Educators and academic institutions$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Pay-As-You-Go$q$, $q$$30$q$, $q$One-time (3,000 credits)$q$, NULL, $q$["3,000 credits","Credits expire after 2 years","AI and plagiarism scanning"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Pro$q$, $q$$14.95/month ($12.95/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["2,000 monthly credits","AI checker, plagiarism checker, fact checker","Readability and grammar checker","SEO content optimizer","Chrome extension","30-day scan history"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Enterprise$q$, $q$$179/month ($136.58/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["15,000 monthly credits","365-day scan history","API access","Dedicated customer success manager","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Originality.ai is a content verification platform that detects AI-generated text, checks for plagiarism, and fact-checks written claims. It was founded in 2022 by Jon Gillham and Conor Watt and is headquartered in Collingwood, Ontario, Canada, built specifically for the content marketing and publishing industry's needs following the rise of generative AI writing tools.$q$, $q$The platform is used primarily by SEO agencies, content marketers, publishers, and educators who need a reliable way to confirm whether text was written by a human, generated by an AI model, or copied from another source before it is published or graded.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The AI detector checks text against outputs from major AI models including ChatGPT, Claude, Gemini, and Grok, while the plagiarism checker identifies global, paraphrased, and patchwork plagiarism against web content. A fact checker cross-references claims in the text against reputable sources to flag potential inaccuracies before publication.$q$, $q$Additional tools include a readability and grammar checker, an SEO content optimizer, a Chrome extension for in-browser scanning, website and domain scanning for ongoing content audits, and team management features that let agencies and publishers share credit pools across multiple seats.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Originality.ai uses a credit-based subscription model where one credit covers roughly 100 words of scanning. The Pro plan starts at 14.95 dollars per month billed monthly, or 12.95 dollars per month billed annually, and includes 2,000 monthly credits.$q$, $q$The Enterprise plan costs 179 dollars per month billed monthly, or 136.58 dollars per month billed annually, for 15,000 monthly credits plus API access and a dedicated customer success manager. A pay-as-you-go option is also available for 30 dollars for 3,000 credits, with credits expiring two years after purchase.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$360-degree customer view$q$, $q$Combines sales, marketing, and service data into a single customer profile.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Open-source Community Edition$q$, $q$Provides free, self-hostable access to the full CRM source code on GitHub.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Flexible workflow engine$q$, $q$Lets companies model custom business processes rather than using fixed pipelines.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Marketing segmentation$q$, $q$Segments customers for targeted campaigns based on behavior and order history.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Role-based access control$q$, $q$Enterprise Edition adds ACL-based user, group, and role management.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Ecommerce integration$q$, $q$Natively integrates with OroCommerce and other ecommerce platforms for unified customer data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$On-premise or cloud deployment$q$, $q$Supports self-hosted on-premise deployment or Oro's managed cloud.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Large dataset support$q$, $q$Enterprise Edition includes PostgreSQL support for handling high-volume customer data.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Free, fully open-source Community Edition with no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Deep customization through the flexible OroPlatform architecture$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Strong native fit for B2B and ecommerce businesses via OroCommerce integration$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Self-hosting option appeals to companies with data residency or compliance needs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Built by a team with prior Magento founding experience$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Active GitHub-based development community$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Requires technical resources to self-host and maintain the Community Edition$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Smaller ecosystem and app marketplace than Salesforce or HubSpot$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Enterprise Edition pricing is not fully transparent and is quote-based$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Steeper learning curve than simpler out-of-the-box CRMs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Smaller company size means a smaller third-party support network$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Best value requires technical teams comfortable with platform customization$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Is OroCRM free?$q$, $q$The Community Edition of OroCRM is free and open source; the Enterprise Edition is paid and quote-based.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Who makes OroCRM?$q$, $q$OroCRM is made by Oro Inc, founded in 2012 in Los Angeles by former Magento leaders Yoav Kutner, Jary Carter, and Dima Soroka.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Can OroCRM be self-hosted?$q$, $q$Yes, OroCRM can be deployed on-premise for self-hosting or in Oro's own cloud.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$How does OroCRM relate to OroCommerce?$q$, $q$OroCRM and OroCommerce are both built on the shared OroPlatform framework, allowing unified customer, order, and marketing data across CRM and ecommerce.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$How much does OroCRM Enterprise Edition cost?$q$, $q$OroCRM Enterprise Edition is quote-based, with third-party estimates citing roughly 116 dollars per user per month as a starting reference point.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Is OroCRM open source?$q$, $q$Yes, the Community Edition source code is publicly available on GitHub under an open-source license.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Who is OroCRM best suited for?$q$, $q$OroCRM is best suited for mid-size and enterprise B2B and ecommerce companies with technical teams that want deep CRM customization.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Who are OroCRM's main competitors?$q$, $q$OroCRM competes with Salesforce, HubSpot, SugarCRM, and open-source alternative SuiteCRM.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$B2B ecommerce customer management$q$, $q$Companies unify customer, order, and marketing data across OroCommerce storefronts and CRM.$q$, $q$B2B and B2C ecommerce companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Self-hosted CRM for compliance-sensitive businesses$q$, $q$Organizations with data residency requirements self-host OroCRM rather than using a SaaS-only CRM.$q$, $q$Regulated or compliance-focused businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Highly customized sales and service workflows$q$, $q$Technical teams build custom business processes using OroCRM's flexible workflow engine.$q$, $q$Systems integrators and technical operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Community Edition$q$, $q$Free$q$, $q$Open source, self-hosted$q$, NULL, $q$["360-degree customer view","Lead and contact management","Basic workflow engine","Self-hosted deployment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$Enterprise Edition$q$, $q$Custom (from approximately $116/user/month)$q$, $q$Contact sales$q$, NULL, $q$["Everything in Community Edition","Role and group access control (ACL)","Advanced customer segmentation","Case management","PostgreSQL support for large datasets","On-premise or cloud deployment"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OroCRM is an open-source CRM platform built by Oro Inc, a company founded in 2012 in Los Angeles by former Magento leaders Yoav Kutner, Jary Carter, and Dima Soroka. OroCRM launched in 2014 as Oro's first product, followed in 2017 by the B2B ecommerce platform OroCommerce, both built on the shared OroPlatform framework.$q$, $q$Because it shares its foundation with OroCommerce, OroCRM is particularly well suited to B2B and ecommerce businesses that want customer, order, and marketing data unified across their storefront and CRM, while its open-source Community Edition gives technical teams full control over customization and hosting.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OroCRM provides a 360-degree customer view combining sales, marketing, and service data, along with a flexible workflow engine that lets companies model custom business processes rather than being locked into rigid, pre-built pipelines. Marketing segmentation and campaign tools support targeted outreach based on customer behavior and order history.$q$, $q$The Enterprise Edition adds role- and group-based access control (ACL), localization for multiple countries and regions, sales and marketing dashboards, case management, and PostgreSQL support for handling large datasets, and can be deployed on-premise or in Oro's own cloud.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63ad3ef7-5046-461f-a151-5b360a08cc61', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OroCRM's Community Edition is free and open source, available for download and self-hosting by any organization, including small businesses that want a no-cost, fully customizable CRM.$q$, $q$The Enterprise Edition is aimed at medium and large organizations and is priced on a custom, quote-based basis; third-party estimates place typical starting costs around 116 dollars per user per month, though actual pricing depends on deployment model, user count, and required modules.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$Unified customer data$q$, $q$Combines behavioral, transactional, and demographic data into a single customer profile.$q$, 0);
