INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$Multi-channel messaging$q$, $q$Sends email, SMS, push notifications, in-app messages, forms, and surveys from one platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$Marketing analytics$q$, $q$Provides reporting dashboards to track campaign and customer journey performance.$q$, 3);
