INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$Ecommerce and SaaS integrations$q$, $q$Connects to ecommerce and SaaS tools to sync customer and transaction data.$q$, 6);
