INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$What is Ortto used for?$q$, $q$Ortto is used for marketing automation and customer journey management, combining customer data, multi-channel messaging, and analytics in one platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$What was Ortto formerly called?$q$, $q$Ortto was formerly known as Autopilot before rebranding in March 2022.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$How much does Ortto cost?$q$, $q$Ortto's Starter plan begins around 199 dollars per month for 5,000 contacts, with Professional and Business plans starting around 509 and 849 dollars per month on annual billing, and custom Enterprise pricing available.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$Who owns Ortto now?$q$, $q$Ortto was acquired by Canva in April 2026 alongside AI workspace startup Simtheory.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$Does Ortto offer a free trial?$q$, $q$Yes, Ortto offers a 14-day free trial with up to 10,000 contacts.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$Who founded Ortto?$q$, $q$Ortto was founded in 2012 by brothers Michael, Chris, and Peter Sharkey.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$Does Ortto support SMS and push notifications?$q$, $q$Yes, Ortto supports email, SMS, push notifications, in-app messages, forms, and surveys.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$Who are Ortto's main competitors?$q$, $q$Ortto competes with HubSpot, ActiveCampaign, and Klaviyo in the marketing automation space.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$Behavior-triggered ecommerce campaigns$q$, $q$Ecommerce brands trigger email and SMS campaigns based on website and purchase behavior.$q$, $q$Ecommerce marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$SaaS customer lifecycle marketing$q$, $q$SaaS companies automate onboarding, upsell, and retention journeys using product usage data.$q$, $q$SaaS marketing and growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$Unified marketing reporting$q$, $q$Marketing teams consolidate campaign, journey, and customer data reporting into one dashboard.$q$, $q$Marketing operations and analytics teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$Starter$q$, $q$$199/month$q$, $q$Monthly$q$, NULL, $q$["Up to 5,000 contacts","Visual journey builder","Email and basic messaging","Standard reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$Professional$q$, $q$$509/month (annual billing)$q$, $q$Annual$q$, NULL, $q$["Up to 10,000 contacts","Multi-channel messaging","Advanced segmentation","Website and activity tracking"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$Business$q$, $q$$849/month (annual billing)$q$, $q$Annual$q$, NULL, $q$["Up to 10,000 contacts","Advanced analytics","Priority support","Expanded automation features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$Enterprise$q$, $q$Custom$q$, $q$Contact sales$q$, NULL, $q$["Custom contact volume","Dedicated support","Custom services and onboarding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ortto is a marketing automation and customer data platform that combines customer data, multi-channel messaging, and analytics in one product. It was founded in 2012 by Australian brothers Michael, Chris, and Peter Sharkey, originally launching as Autopilot in 2015 before rebranding to Ortto in March 2022 to reflect a broader focus beyond automation alone.$q$, $q$Headquartered in Sydney, Australia, with additional operations in San Francisco, Ortto serves more than 11,000 customers globally, including Atlassian, Microsoft, and Patreon. In April 2026, Ortto was acquired by design platform Canva alongside AI workspace startup Simtheory as part of Canva's expansion into marketing automation and agentic AI.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Ortto ingests behavioral, transactional, and demographic customer data to build a unified customer profile, then lets marketing teams design customer journeys using a visual, drag-and-drop journey builder. Messaging spans email, SMS, push notifications, in-app messages, forms, and surveys rather than being limited to a single channel.$q$, $q$The platform also includes marketing analytics and reporting dashboards, website and product activity tracking, and AI-assisted content and audience segmentation, along with integrations for ecommerce and SaaS tools to trigger campaigns based on real customer behavior.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6216dfaa-05dd-4223-a596-dbb3ee514d3c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Ortto's pricing scales with contact volume. The Starter plan begins around 199 dollars per month for up to 5,000 contacts, while Professional plans start around 509 dollars per month on annual billing for 10,000 contacts, and Business plans run about 849 dollars per month annually with more advanced analytics.$q$, $q$Enterprise plans are custom-quoted based on scale and services required. Extra contacts and email volume are available as add-ons, and a 14-day free trial with up to 10,000 contacts is available for new customers.$q$]::text[], 2);
