-- Enrichment marathon batch: Orb, Orca Security, Order.co, Ordway, Orgvue, Originality.ai, OroCRM, Ortto

-- в”Ђв”Ђ Orb в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Orb is a usage-based billing and revenue automation platform that lets B2B software and AI companies meter product usage and launch hybrid pricing models without custom engineering.$q$, short_description),
  pricing_model = COALESCE($q$Custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom (contact sales)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Orb Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Orb review: usage-based billing and revenue automation for B2B software and AI companies. Features, custom pricing, and top alternatives compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Orb (withorb.com) is a usage-based billing and revenue automation platform built for B2B software and AI companies that need to meter product usage and launch complex, hybrid pricing models without custom engineering. The company was founded in 2021 by Alvaro Morales and Kshitij Grover, two former engineering leaders at Asana who grew frustrated with the limitations of existing billing tools and set out to build billing infrastructure flexible enough for modern usage-based and consumption pricing. Orb launched publicly in March 2023 and is headquartered in San Francisco, California. Its core product ingests raw product usage events into what Orb calls a Revenue Graph, then lets finance, product, and engineering teams define pricing logic on top of that data covering subscription, usage-based, and hybrid models, generate accurate invoices (including backdated and backfilled data), enforce spend controls and usage alerts, and run revenue simulations before launching new pricing. Orb also offers Experience Kit for customer-facing billing dashboards and checkout, and supports ASC 606-aligned, audit-ready revenue workflows. Its main differentiators versus legacy billing systems are speed of iterating on pricing through version-controlled, rapid-deploy price changes, native support for high-volume event ingestion needed by AI and infrastructure companies billing by API call or token, and deep integrations with Salesforce, NetSuite, and data warehouses. Pricing is entirely custom and quote-based, structured around two metrics: billings (the total value of invoices issued to end customers through Orb) and events (raw usage records ingested), with Core, Advanced, and Enterprise tiers; Advanced and Enterprise add a platform fee plus premium support and enterprise SLAs. Orb's target customers are growth-stage and enterprise B2B software companies, particularly in AI infrastructure, cloud platforms, and developer tools; publicly named customers include Vercel, Supabase, Redis, and LaunchDarkly. In June 2026 payments company Adyen announced a definitive agreement to acquire Orb for 335 million dollars to unify billing and payments infrastructure for enterprise merchants; the deal closed on July 1, 2026, making Orb an indirect, wholly owned subsidiary of Adyen operated under an incubator model. Before the acquisition Orb had raised roughly 44 million dollars from investors including Greylock and Menlo Ventures. Orb's main competitors in the usage-based billing and monetization space include Metronome, Zuora, Chargebee, and Stripe Billing.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a1062364-3f5b-45dc-b882-5a0283cbb0a9';

