-- в”Ђв”Ђ Orca Security в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Orca Security is an agentless cloud-native application protection platform (CNAPP) that scans AWS, Azure, GCP, and Kubernetes environments for vulnerabilities, misconfigurations, and compliance risks without deploying agents.$q$, short_description),
  pricing_model = COALESCE($q$Custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom (contact sales)$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$501-1000 employees$q$, company_size),
  headquarters = COALESCE($q$Tel Aviv, Israel$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Orca Security Review 2026: Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Orca Security review: agentless CNAPP for AWS, Azure, and GCP. SideScanning technology, key features, custom pricing, and top competitors compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Orca Security (orca.security) is an agentless cloud-native application protection platform (CNAPP) that identifies, prioritizes, and helps remediate security risks and compliance issues across AWS, Azure, Google Cloud, and Kubernetes environments. The company was founded in 2018 by Avi Shua and Gil Geron, cybersecurity veterans who previously worked together, with Shua serving as CEO; Orca is headquartered in Tel Aviv, Israel, with a significant US presence including offices in Portland, Oregon. Orca's core differentiator is its patented SideScanning technology, which reads cloud workload data directly from the cloud provider's infrastructure layer rather than requiring an agent to be installed on every virtual machine, container, or serverless function, reducing deployment friction and eliminating coverage gaps caused by unmonitored assets. On top of SideScanning, Orca layers a Unified Data Model that correlates vulnerabilities, misconfigurations, identity and entitlement risk (CIEM), malware, and sensitive data exposure into prioritized attack-path narratives rather than raw alert lists, and it has since added Orca Sensor for runtime observability, an AI reasoning engine for automated triage, and dedicated modules for AI security posture and code security scanning earlier in the development lifecycle. Orca has grown quickly, raising a total of about 632 million dollars in venture funding, including a 550 million dollar extended Series C at a 1.8 billion dollar valuation led by Temasek with participation from CapitalG, Redpoint Ventures, GGV, and ICONIQ Capital, reaching unicorn status within roughly two years of launch. The company reports more than 500 employees as of 2026. Orca targets mid-market and enterprise security teams, cloud security, DevSecOps, and compliance groups at organizations running multi-cloud or hybrid-cloud infrastructure who need broad, fast-to-deploy visibility without managing agent fleets; named customers include Autodesk, Swiggy, Sisense, and C6 Bank. Pricing is not published and is sold through a custom, sales-led enterprise contract model based on workload counts and modules purchased. Orca competes most directly with Wiz, Palo Alto Networks Prisma Cloud, Lacework, and Aqua Security in the fast-consolidating CNAPP category, where agentless-versus-agent-based coverage and unified risk prioritization are the primary points of differentiation among vendors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'de412e9f-bb56-438d-8972-125d8b06d414';

